function getFilteredDestinations(type: string, vibe: string, region: string): Destination[] {
  const exact = ALL_DESTINATIONS.filter(d => {
    const typeMatch = !type || type === "any" || d.type.includes(type);
    const vibeMatch = !vibe || vibe === "any" || vibe === "mix" || d.vibe.includes(vibe);
    const regionMatch = !region || region === "any" || d.region === region;
    return typeMatch && vibeMatch && regionMatch;
  });

  if (exact.length >= 8) return exact.slice(0, 36);

  // Broaden: drop vibe filter, keep type + region
  const byTypeRegion = ALL_DESTINATIONS.filter(d => {
    const typeMatch = !type || type === "any" || d.type.includes(type);
    const regionMatch = !region || region === "any" || d.region === region;
    return typeMatch && regionMatch;
  });

  if (byTypeRegion.length >= 5) return byTypeRegion.slice(0, 36);

  // Final fallback: just region
  return ALL_DESTINATIONS.filter(d => !region || region === "any" || d.region === region).slice(0, 36);
}

function buildQuestions(a: Answers): Question[] {
  const qs: Question[] = [
    {
      key: "stagType", question: "What type of stag?", sub: "The most important decision. Everything else narrows from here.",
      education: "The biggest stag mistake is planning the one you think you should have rather than the one your group will actually enjoy. Be honest about who is coming and what they would genuinely get out of.",
      options: [...STAG_TYPES.map(t => ({ id: t.id, label: t.label, desc: t.desc })), { id: "any", label: "Not sure yet \u2014 show me everything", desc: "No decision needed. Browse every kind of stag and see what jumps out." }],
      groomsSay: [
        { quote: "I thought I wanted a big city party. What I actually wanted was great food and laughing with my best mates. The relaxed version was better.", author: "u/honestgroom" },
        { quote: "Ski stag. Everyone said they were not good enough. Everyone loved it.", author: "u/skistag" },
      ],
    },
    {
      key: "groomVibe",
      question: "What does he actually enjoy?",
      sub: "This shapes the destination suggestions. Be honest about who he is, not who you think he should be.",
      education: "The best stag is planned for the actual person. A groom who never goes clubbing won't suddenly love Ibiza just because it's his stag.",
      options: GROOM_VIBES.map(v => ({ id: v.id, label: v.label, desc: v.desc })),
      groomsSay: [
        { quote: "We picked Vegas because that's what you do. He would have loved the Highlands with good whisky and clay shooting. We didn't ask.", author: "u/hindsight" },
        { quote: "Food tour in Porto. Nobody thought it was a stag activity. Everyone said it was the best day.", author: "u/portostag" },
      ],
    },
    {
      key: "region", question: "UK, Europe, or further afield?", sub: "Budget and travel complexity differ significantly.",
      education: "UK and Ireland means no flights, no passport checks, and easier logistics for the whole group. Europe adds 2-3 hours of travel but unlocks extraordinary value and variety. Long haul means a proper trip but costs significantly more.",
      options: [
        { id: "uk-ireland", label: "UK or Ireland", desc: "No flights needed. Edinburgh, Newquay, Lake District, Dublin, hired country house — massive variety without leaving the islands.", pros: ["No passports", "No flight stress", "More flexibility on dates", "Easier if anyone is nervous about travel"] },
        { id: "europe", label: "Europe", tag: "Most popular", desc: "Krakow, Budapest, Ibiza, ski resorts, Portugal, Croatia. Flights typically under £150 return.", pros: ["Extraordinary value", "More variety than UK", "Proper change of scene"] },
        { id: "longhaul", label: "Long haul", desc: "Vegas, Bangkok, Cape Town, New Zealand, Canada. A proper trip, a genuinely different experience.", pros: ["Truly memorable", "Places most people never otherwise visit"], cons: ["3-5x the cost of Europe", "Requires more planning", "Check passports — all must be valid 6 months beyond travel date"] },
        { id: "any", label: "Don't mind", desc: "Show destinations from everywhere — UK, Europe and long haul side by side." },
      ],
      groomsSay: [
        { quote: "Krakow. 8 of us, 3 nights, £280 each all in including flights. Impossible to beat.", author: "u/stagplanner" },
        { quote: "We went to Vegas. 10 of us, £1,600 each. Absolutely worth every penny.", author: "u/vegasstag" },
        { quote: "Scottish Highlands hired house. Six of us, hot tub, clay shooting. One of the best weekends of my life.", author: "u/housestag" },
      ],
    },
    {
      key: "groupSize", question: "How many people?",
      education: "Under 8 is easy to manage. 8-15 is the most common size. Over 15 requires early booking and a very organised best man. Expect at least 3 people to drop out from your original invite list — factor this in before booking minimum numbers.",
      options: [
        { id: "small", label: "Under 8", tag: "Easy to plan", desc: "Maximum flexibility. Almost any option works at this size. More intimate but easier to coordinate." },
        { id: "medium", label: "8-15", tag: "Most common", desc: "The classic stag size. Book accommodation early. Average UK stag do group is 13." },
        { id: "large", label: "15-25", desc: "Requires early planning and firm deposit deadlines. Consider a stag company for logistics." },
        { id: "huge", label: "25+", desc: "Essentially an event. A stag specialist company is worth the fee at this size." },
        { id: "unknown", label: "Not sure yet", desc: "Completely fine — the invite list usually settles itself once a date is locked." },
      ],
      groomsSay: [{ quote: "10 people. Big enough to be a party, small enough that nobody got left behind.", author: "u/tenpeople" }],
    },
    {
      key: "budget", question: "Budget per person?", sub: "Set this before you plan anything else. Then present it to the group before booking anything.",
      education: "Include flights, accommodation, one group activity, food, and drinks for the weekend. The best man should collect a deposit before booking anything — once money is paid, dropouts become rare. Anyone who drops out should still contribute to fixed costs.",
      options: [
        { id: "under250", label: "Under £250 pp", desc: "UK or budget Eastern European city. Very achievable with good planning." },
        { id: "250-400", label: "£250-£400 pp", tag: "Most stags", desc: "Covers flights to Europe, good accommodation, an activity, and nights out." },
        { id: "400-700", label: "£400-£700 pp", desc: "More comfortable. Beach destinations, ski trips, or better accommodation." },
        { id: "700-1500", label: "£700-£1,500 pp", desc: "Ski resorts, luxury beach, Dubai territory." },
        { id: "1500plus", label: "£1,500+ pp", desc: "Vegas, long haul, or a genuinely extraordinary experience anywhere." },
        { id: "unknown", label: "No budget set yet", desc: "Also fine — but agree one with the group before anything gets booked." },
      ],
      groomsSay: [{ quote: "Collect deposits before you book anything. Sounds obvious. Not everyone does it.", author: "u/bestmanadvice" }],
    },
  ];

  if (a.stagType && a.region) {
    const vibe = a.groomVibe || "mix";
    const filtered = getFilteredDestinations(a.stagType, vibe, a.region);
    if (filtered.length > 0) {
      const exactCount = ALL_DESTINATIONS.filter(d => d.type.includes(a.stagType) && d.region === a.region).length;
      const isBroadened = exactCount < 5;
      qs.push({
        key: "destination",
        question: "Which destination?",
        sub: a.stagType === "any" || a.region === "any"
          ? "The full list — browse and see what jumps out."
          : isBroadened
          ? "Showing all destinations in this region — broadened from your stag type. All are worth considering."
          : "Matched to your stag type and his vibe.",
        education: "Stag-friendliness ratings are based on real experience from groups — it varies more than you'd expect. 'Oh great idea' tags mark destinations most groups haven't considered but which consistently deliver.",
        options: (filtered.map(d => {
          const photo = DESTINATION_PHOTOS[d.id] || GENERIC_FALLBACK_PHOTO;
          return {
            id: d.id,
            label: `${d.label} · ${d.country}`,
            tag: d.tag,
            desc: d.desc, stagInfo: d.stagInfo, meta: d.meta,
            img: photo.imageUrl,
            photoCredit: { name: photo.photographer, url: photo.photographerUrl },
            aff: d.aff,
          };
        }) as Option[]).concat([{ id: "undecided", label: "Still deciding", desc: "Skip this for now. You'll get your shortlist to come back to — no transport questions until you've picked somewhere." }]),
        groomsSay: [
          { quote: "Budapest was a revelation. Nobody in our group had been. That made it feel special.", author: "u/budapestfan" },
          { quote: "Hired a house in Wales. Six of us, hot tub, clay shooting. One of the best weekends of my life.", author: "u/housestag" },
          { quote: "Belgrade. Nobody believed me when I suggested it. Everyone is still talking about it two years later.", author: "u/belgradesurprise" },
        ],
      });
    }
  }

  if (a.destination && a.destination !== "undecided") qs.push({
    key: "transport", question: "How is everyone getting there?",
    education: "For UK stags, a minibus is often cheaper and more practical than everyone booking trains separately. For abroad, check passports well in advance — one expired passport has ruined more stags than anything else. Set a firm confirmation deadline and stick to it.",
    options: [
      { id: "minibus", label: "Minibus hire", price: "£200-£400", desc: "Everyone together, nobody has to drive, flexible on timings. Best for UK trips.", aff: { label: "Get quotes on Coach Hire", url: "https://www.coachhire.com/quote/" } },
      { id: "train", label: "Train", desc: "Easier for city destinations. Agree on arrival times early — staggered arrivals always cause problems.", aff: { label: "Book on Trainline", url: "https://www.thetrainline.com" } },
      { id: "flights", label: "Flights", desc: "Book as a group for better coordination. One person manages all booking details. Check passports now.", aff: { label: "Search on Skyscanner", url: "https://www.skyscanner.net" } },
      { id: "drive", label: "Drive (car share)", desc: "Only works for smaller groups going to accessible UK locations. Agree designated drivers early.", aff: { label: "Find parking on JustPark", url: "https://www.justpark.com" } },
      { id: "mixed", label: "Meeting there", desc: "Some arrive together, some independently. Happens with larger groups or when people are coming from different parts of the UK.", aff: { label: "Compare trains on Trainline", url: "https://www.thetrainline.com" } },
    ],
    groomsSay: [
      { quote: "Minibus door to door. Nobody had to navigate, nobody was late. Worth every penny.", author: "u/minibussorted" },
      { quote: "Check passports six months out. No exceptions. At least one will need renewing.", author: "u/passportadvice" },
    ],
  });

  return qs;
}

const TYPE_PHRASES: Record<string, string> = {
  "city-party": "city break with big nights out", beach: "beach and sun stag", ski: "ski stag",
  golf: "golf stag", adventure: "adventure stag", relaxed: "relaxed, social stag",
  luxury: "luxury stag", budget: "maximum-value stag", hiking: "hiking and outdoors stag",
  culture: "culture and food stag", any: "stag weekend",
};
const SIZE_PHRASES: Record<string, string> = { small: "under 8", medium: "8–15", large: "15–25", huge: "25+" };
const BUDGET_PHRASES: Record<string, string> = {
  under250: "under £250", "250-400": "£250–£400", "400-700": "£400–£700",
  "700-1500": "£700–£1,500", "1500plus": "£1,500+",
};
const TRANSPORT_PHRASES: Record<string, string> = {
  minibus: "minibus hire", train: "by train", flights: "flying", drive: "driving in a car share", mixed: "everyone making their own way there",
};

type Guest = { name: string; phone: string; dietary: string; paid: boolean };
function HandoverEditor({ guests, setGuests, bestMan, setBestMan, stagNotes, setStagNotes, shared, setShared, groomName, dest }: {
  guests: Guest[]; setGuests: (v: Guest[] | ((p: Guest[]) => Guest[])) => void;
  bestMan: string; setBestMan: (v: string | ((p: string) => string)) => void;
  stagNotes: string; setStagNotes: (v: string | ((p: string) => string)) => void;
  shared: boolean; setShared: (v: boolean) => void;
  groomName?: string; dest?: Destination;
}) {
  return (
    <>
      <div style={{ marginBottom: 32 }}>
        <div>
            <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 22, color: T.ink, marginBottom: 20 }}>The handover</div>
            <GoodToKnow>
              Your one job as the groom: the guest list. Add names and numbers below, then hand the whole thing to your best man with one link. He gets everyone's contact details, your notes, and the destination if you've chosen one — everything he needs to start the WhatsApp group.
            </GoodToKnow>
            <div style={{ background: T.white, border: "1px solid " + T.rule, borderRadius: 4, padding: 24, marginBottom: 16 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", color: T.mid }}>Guest list</div>
                <button
                  onClick={() => setGuests(g => [...g, { name: "", phone: "", dietary: "", paid: false }])}
                  style={{ background: T.navy, color: "white", border: "none", padding: "6px 14px", fontSize: 11, fontWeight: 700, cursor: "pointer", borderRadius: 2 }}>
                  + Add person
                </button>
              </div>
              {guests.map((g, i) => (
                <div key={i} style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr auto", gap: 10, marginBottom: 10 }}>
                  {(["name", "phone", "dietary"] as const).map(f => (
                    <input
                      key={f}
                      placeholder={f === "name" ? "Name" : f === "phone" ? "Phone" : "Dietary needs"}
                      value={g[f]}
                      onChange={e => setGuests(gs => gs.map((x, idx) => idx === i ? { ...x, [f]: e.target.value } : x))}
                      style={{ padding: "8px 12px", border: "1px solid " + T.rule, borderRadius: 2, fontSize: 13, fontFamily: "Inter", background: T.paper, color: T.ink }}
                    />
                  ))}
                  <button onClick={() => setGuests(gs => gs.filter((_, idx) => idx !== i))} style={{ background: "none", border: "none", color: T.mid, cursor: "pointer", fontSize: 16 }}>&#215;</button>
                </div>
              ))}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 10, marginTop: 16 }}>
                <input
                  placeholder="Best man's name"
                  value={bestMan}
                  onChange={e => setBestMan(e.target.value)}
                  style={{ padding: "8px 12px", border: "1px solid " + T.rule, borderRadius: 2, fontSize: 13, fontFamily: "Inter", background: T.paper, color: T.ink }}
                />
                <input
                  placeholder="Notes for him — dates that work, budget ceiling, anyone to keep an eye on..."
                  value={stagNotes}
                  onChange={e => setStagNotes(e.target.value)}
                  style={{ padding: "8px 12px", border: "1px solid " + T.rule, borderRadius: 2, fontSize: 13, fontFamily: "Inter", background: T.paper, color: T.ink }}
                />
              </div>
              <div style={{ marginTop: 12, fontSize: 12, color: T.mid }}>{guests.filter(g => g.name.trim()).length} on the list</div>
            </div>
            {(() => {
              const payload = {
                g: groomName || undefined,
                b: bestMan.trim() || undefined,
                dest: dest?.label,
                country: dest?.country,
                notes: stagNotes.trim() || undefined,
                guests: guests.filter(g => g.name.trim()).map(g => ({ n: g.name.trim(), p: g.phone.trim(), d: g.dietary.trim() })),
              };
              const link = window.location.origin + window.location.pathname + "#handover=" + encodeHandover(payload);
              const waText = encodeURIComponent(
                (bestMan.trim() ? bestMan.trim() + " — " : "") +
                "you're the best man. Here's the stag list, over to you: " + link
              );
              const canShare = payload.guests.length > 0;
              return (
                <div>
                  <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                    <button
                      disabled={!canShare}
                      onClick={() => {
                        navigator.clipboard.writeText(link).then(() => {
                          setShared(true);
                          setTimeout(() => setShared(false), 2500);
                        });
                      }}
                      style={{ background: canShare ? T.dark : T.rule, color: "white", border: "none", padding: "12px 24px", fontSize: 12, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", cursor: canShare ? "pointer" : "not-allowed", borderRadius: 2 }}>
                      {shared ? "\u2713 Link copied" : "Copy handover link"}
                    </button>
                    <a
                      href={canShare ? "https://wa.me/?text=" + waText : undefined}
                      target="_blank" rel="noopener noreferrer"
                      style={{ background: canShare ? "#25795A" : T.rule, color: "white", textDecoration: "none", padding: "12px 24px", fontSize: 12, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase", borderRadius: 2, pointerEvents: canShare ? "auto" : "none", display: "inline-block" }}>
                      Send on WhatsApp &rarr;
                    </a>
                  </div>
                  <div style={{ marginTop: 12, fontSize: 12, color: T.mid, lineHeight: 1.6, maxWidth: 520 }}>
                    The link itself carries the list — nothing is stored on a server. It contains names and phone numbers, so only share it with your best man.
                  </div>
                </div>
              );
            })()}
        </div>
      </div>
    </>
  );
}

export function StagModule({ groomName }: { groomName?: string }) {
  const [phase, setPhase] = useState<"intro" | "journey" | "summary" | "organiser">("intro");
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState<Answers>({});
  const [guests, setGuests] = usePersistentState<{ name: string; phone: string; dietary: string; paid: boolean }[]>("stag-guests", [{ name: "", phone: "", dietary: "", paid: false }]);
  const [bestMan, setBestMan] = usePersistentState<string>("stag-bestman", "");
  const [stagNotes, setStagNotes] = usePersistentState<string>("stag-notes", "");
  const [shared, setShared] = useState(false);

  const questions = buildQuestions(answers);
  const currentQ = questions[step];

  const choose = (val: string) => {
    const next = { ...answers, [currentQ.key]: val };
    setAnswers(next);
    const qs = buildQuestions(next);
    if (step + 1 < qs.length) setStep(step + 1);
    else setPhase("summary");
  };

  if (phase === "intro") return (
    <IntroScreen
      eyebrow="Stag · Planning guide"
      title="Find the right stag for your group."
      description="From a ski trip in Whistler to a night in Belgrade to a hired house in the Lake District — this covers every type of stag, filters to what suits your group, and gives you the information you need to actually plan it. Not just a destination list."
      steps={["Type", "His vibe", "Region", "Group size", "Budget", "Destination", "Transport"]}
      quote="We spent three weeks in a WhatsApp group going in circles. Wish we had just made the decisions in order like this."
      quoteAuthor="u/stagorganiser"
      illustration={<div style={{ display: "flex", gap: 16 }}><CityIllus city="krakow" /><CityIllus city="valThorens" /></div>}
      onStart={() => setPhase("journey")}
      secondaryLabel="Or jump straight to the guest list"
      onSecondary={() => setPhase("organiser")}
    />
  );

  if (phase === "organiser") {
    const dest = ALL_DESTINATIONS.find(d => d.id === answers.destination);
    return (
      <div>
        <button onClick={() => setPhase("intro")} style={{ background: "none", border: "none", fontSize: 12, fontWeight: 600, color: T.mid, letterSpacing: "0.08em", textTransform: "uppercase", cursor: "pointer", marginBottom: 32 }}>← Back</button>
        <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.2em", textTransform: "uppercase", color: T.mid, marginBottom: 14 }}>Stag · Guest list</div>
        <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 34, color: T.ink, marginBottom: 24, maxWidth: 520, lineHeight: 1.15 }}>Build the list. Hand it over.</div>
        <HandoverEditor guests={guests} setGuests={setGuests} bestMan={bestMan} setBestMan={setBestMan} stagNotes={stagNotes} setStagNotes={setStagNotes} shared={shared} setShared={setShared} groomName={groomName} dest={dest} />
      </div>
    );
  }

  if (phase === "journey") {
    const chosen = answers[currentQ.key];
    return (
      <div>
        <Progress step={step + 1} total={questions.length} onBack={step > 0 ? () => setStep(step - 1) : null} />
        <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 32, color: T.ink, marginBottom: 6 }}>{currentQ.question}</div>
        {currentQ.sub && <div style={{ fontSize: 14, color: T.mid, marginBottom: currentQ.education ? 16 : 28, lineHeight: 1.6 }}>{currentQ.sub}</div>}
        {currentQ.education && <GoodToKnow>{currentQ.education}</GoodToKnow>}
        {currentQ.options.some((opt: Option) => opt.img) ? (
          <div className="options-grid-photo">
            {currentQ.options.map((opt: Option, i: number) => (
              <OptionCard key={i} opt={opt} isChosen={chosen === (opt.id || opt.label)} onChoose={() => choose(opt.id || opt.label)} portrait />
            ))}
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12, marginBottom: 8 }}>
            {currentQ.options.map((opt: Option, i: number) => (
              <OptionCard key={i} opt={opt} isChosen={chosen === (opt.id || opt.label)} onChoose={() => choose(opt.id || opt.label)} />
            ))}
          </div>
        )}
        {currentQ.groomsSay && <GroomsSay quotes={currentQ.groomsSay} />}
      </div>
    );
  }

  const dest = ALL_DESTINATIONS.find(d => d.id === answers.destination);
  const undecided = !dest;

  const typePhrase = TYPE_PHRASES[answers.stagType] || "stag weekend";
  const wherePhrase = dest
    ? `in ${dest.label}`
    : answers.region === "uk-ireland" ? "somewhere in the UK or Ireland"
    : answers.region === "europe" ? "somewhere in Europe"
    : answers.region === "longhaul" ? "somewhere long haul"
    : "";
  const sizePhrase = SIZE_PHRASES[answers.groupSize];
  const budgetPhrase = BUDGET_PHRASES[answers.budget];
  const transportPhrase = TRANSPORT_PHRASES[answers.transport];
  const summarySentence =
    `A ${typePhrase}` +
    (wherePhrase ? ` ${wherePhrase}` : "") +
    (sizePhrase ? `, for a group of ${sizePhrase}` : "") +
    (budgetPhrase ? `, at ${budgetPhrase} a head` : "") + "." +
    (transportPhrase ? ` Getting there: ${transportPhrase}.` : "");

  return (
    <div>
      <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 34, color: T.ink, marginBottom: 6 }}>Your stag plan.</div>
      <div style={{ fontSize: 14, color: T.mid, marginBottom: 24, lineHeight: 1.65 }}>
        Share this with your best man or use it as the starting point for your planning conversation.
      </div>

      <div style={{ background: T.white, border: "1px solid " + T.rule, borderRadius: 4, padding: "28px 32px", marginBottom: 32 }}>
        <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 24, color: T.ink, lineHeight: 1.4 }}>{summarySentence}</div>
        {undecided && (
          <div style={{ marginTop: 16, paddingTop: 16, borderTop: "1px solid " + T.rule, display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap" }}>
            <div style={{ fontSize: 13, color: T.mid }}>Destination still open — completely fine at this stage.</div>
            <button
              onClick={() => { const i = questions.findIndex(q => q.key === "destination"); if (i >= 0) { setPhase("journey"); setStep(i); } }}
              style={{ background: "none", border: "none", padding: 0, fontSize: 12, fontWeight: 700, color: T.navy, letterSpacing: "0.06em", textTransform: "uppercase", cursor: "pointer", borderBottom: "1px solid " + T.navy }}>
              Revisit your shortlist →
            </button>
          </div>
        )}
      </div>

      {dest && (
        <div style={{ background: T.navyLight, border: "1px solid " + T.rule, borderRadius: 4, padding: "24px", marginBottom: 32 }}>
          <div style={{ fontFamily: "'DM Serif Display', serif", fontSize: 20, color: T.ink, marginBottom: 6 }}>{dest.label}</div>
          <div style={{ fontSize: 13, color: T.mid, marginBottom: 8 }}>{dest.stagInfo}</div>
          <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginBottom: 16 }}>
            {Object.entries(dest.meta).map(([k, v]) => (
              <div key={k} style={{ fontSize: 12, color: T.mid }}>
                <span style={{ fontWeight: 600, color: T.ink }}>{k}:</span> {v}
              </div>
            ))}
          </div>
          <AffLink label={dest.aff.label} url={dest.aff.url} />
        </div>
      )}

      <HandoverEditor guests={guests} setGuests={setGuests} bestMan={bestMan} setBestMan={setBestMan} stagNotes={stagNotes} setStagNotes={setStagNotes} shared={shared} setShared={setShared} groomName={groomName} dest={dest} />

      <button
        onClick={() => { setPhase("intro"); setAnswers({}); setStep(0); }}
        style={{ background: "none", border: "1px solid " + T.rule, color: T.mid, padding: "12px 20px", fontSize: 12, fontWeight: 600, cursor: "pointer", borderRadius: 2 }}>
        Start over
      </button>
    </div>
  );
}
